inline const char* XccLookup(uint32_t hash) {
    int lo = 0, hi = kXccNameCount - 1;
    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        if (kXccNames[mid].hash == hash) return kXccNames[mid].name;
        if (kXccNames[mid].hash < hash) lo = mid + 1;
        else hi = mid - 1;
    }
    return nullptr;
}

